// ?箸蝐餃?摰?
import { StateEffect, StateField } from "@codemirror/state";

export interface Position {
  line: number;
  col: number;
  offset: number;
}

export inte

rface Range {
  from: Position;
  to: Position;
}

// ??桃??
export interface HeadingCache {
  heading: string;
  level: number;
  position: {
    start: Position;
    end: Position;
  };
}

export interface TagCache {
  tag: string;
  position: {
    start: Position;
    end: Position;
  };
}

export interface LinkCache {
  link: string;
  displayText?: string;
  position: {
    start: Position;
    end: Position;
  };
}

export interface FrontmatterCache {
  [key: string]: any;
  position: {
    start: Position;
    end: Position;
  };
}

export interface CachedMetadata {
  headings?: HeadingCache[];
  tags?: TagCache[];
  links?: LinkCache[];
  frontmatter?: FrontmatterCache;
}

// ?辣?詨
export class TFile {
  path: string;
  name: string;
  basename: string;
  extension: string;
  stat: {
    ctime: number;
    mtime: number;
    size: number;
  };

  constructor(path?: string) {
    this.path = path || '';
    if (path) {
      const parts = path.split('/');
      this.name = parts[parts.length - 1];
      const nameParts = this.name.split('.');
      this.extension = nameParts.pop() || '';
      this.basename = nameParts.join('.');
    } else {
      this.name = '';
      this.extension = '';
      this.basename = '';
    }
    this.stat = {
      ctime: Date.now(),
      mtime: Date.now(),
      size: 0
    };
  }
}

// Vault 蝐餅芋??
export class Vault {
  private files: Map<string, string> = new Map();

  async cachedRead(file: TFile): Promise<string> {
    return this.read(file);
  }

  async read(file: TFile): Promise<string> {
    const content = this.files.get(file.path);
    if (content === undefined) {
      throw new Error(`File not found: ${file.path}`);
    }
    return content;
  }

  async modify(file: TFile, data: string): Promise<void> {
    this.files.set(file.path, data);
  }

  getFiles(): TFile[] {
    return Array.from(this.files.keys()).map(path => new TFile(path));
  }

  getAbstractFileByPath(path: string): TFile | null {
    return this.files.has(path) ? new TFile(path) : null;
  }

  // ?其?瘚????拇瘜?
  _addFile(path: string, content: string): TFile {
    this.files.set(path, content);
    return new TFile(path);
  }
}

// MetadataCache 蝐餅芋??
export class MetadataCache {
  private cache: Map<string, CachedMetadata> = new Map();

  getFileCache(file: TFile): CachedMetadata | null {
    return this.cache.get(file.path) || null;
  }

  // ?其?瘚????拇瘜?
  _setFileCache(file: TFile, metadata: CachedMetadata): void {
    this.cache.set(file.path, metadata);
  }
}

// App 蝐餅芋??
export function parseYaml(yaml: string): any {
  try {
    // Keep this mock lightweight but compatible with Obsidian's API.
    // eslint-disable-next-line @typescript-eslint/no-var-requires
    const jsYaml = require("js-yaml");
    return jsYaml.load(String(yaml ?? ""));
  } catch {
    return null;
  }
}

export class App {
  vault: Vault;
  metadataCache: MetadataCache;
  workspace: {
    activeLeaf?: {
      view: any;
    };
    on: any;
    getLeaf?: any;
  };
  plugins: {
    plugins: Record<string, any>;
  };

  constructor() {
    this.vault = new Vault();
    this.metadataCache = new MetadataCache();
    this.workspace = {
      activeLeaf: undefined,
      on: function() { return null; },
      getLeaf: function() {
        return {
          openFile: async function() { return null; },
        };
      },
    };
    this.plugins = {
      plugins: {}
    };
  }
}

// Plugin 蝐餅芋??
export abstract class Plugin {
  app: App;
  manifest: {
    id: string;
    name: string;
    version: string;
    minAppVersion: string;
    description: string;
    author: string;
    authorUrl: string;
    isDesktopOnly: boolean;
  };

  constructor(app: App, manifest: any) {
