  basename: string;
  extension: string;
  stat: {
    ctime: number;
    mtime: number;
    size: number;
  };

  constructor(path?: string) {
    this.path = path || '';
    if (path) {
      const parts = path.split('/');
      this.name = parts[parts.length - 1];
      const nameParts = this.name.split('.');
      this.extension = nameParts.pop() || '';
      this.basename = nameParts.join('.');
    } else {
      this.name = '';
      this.extension = '';
