  addToggle(cb: (toggle: ToggleComponent) => void): this {
    const toggle: any = {
      setValue: () => toggle,
      onChange: () => toggle,
    };
    cb(toggle as ToggleComponent);
    return this;
  }

  addDropdown(cb: (dropdown: DropdownComponent) => void): this {
    const dropdown: any = {
      addOption: () => dropdown,
      setValue: () => dropdown,
      onChange: () => dropdown,
    };
    cb(dropdown as DropdownComponent);
    return this;
  }

  addSlider(cb: (slider: SliderComponent) => void): this {
    const slider: any = {
      setLimits: () => slider,
      setValue: () => slider,
      setDynamicTooltip: () => slider,
      onChange: () => slider,
    };
    cb(slider as SliderComponent);
    return this;
  }

  addText(cb: (text: TextComponent) => void): this {
    const text: any = {
      setPlaceholder: () => text,
      setValue: () => text,
      setDisabled: () => text,
      onChange: () => text,
    };
    cb(text as TextComponent);
    return this;
  }

  addSearch(cb: (search: TextComponent) => void): this {
    return this.addText(cb);
  }

  addButton(cb: (button: ButtonComponent) => void): this {
    const button: any = {
      setButtonText: () => button,
      setCta: () => button,
      setDisabled: () => button,
      onClick: () => button,
    };
    cb(button as ButtonComponent);
    return this;
  }

