export class TFolder extends TFile {
  children: Array<TFile | TFolder> = [];

  constructor(path?: string) {
    super(path);
  }
}

export const prepareFuzzySearch = (query: string) => {
  const q = String(query ?? "").toLowerCase();
  return (text: string) => String(text ?? "").toLowerCase().includes(q);
};

export class Modal {
  app: App;
  titleEl: HTMLElement;
  contentEl: HTMLElement;

  constructor(app: App) {
    this.app = app;
    this.titleEl = enhanceEl(document.createElement('div'));
    this.contentEl = enhanceEl(document.createElement('div'));
  }

  open(): void {
    if (typeof (this as any).onOpen === 'function') (this as any).onOpen();
  }

  close(): void {
    if (typeof (this as any).onClose === 'function') (this as any).onClose();
  }
}

